  const total = Number(user.total_tasks_today || 0);
  const completed = Number(user.completed_tasks_today || 0);

  if (total === 0) continue;

  // 🔥 Dynamic Calculations
  const monthly = yearly / 12;
  const dailyPool = (monthly * 0.5) / workingDays;   // 50% monthly for daily
