  const ratio = completed / total;
  let points = ratio * taskPool;

  // Safety cap
  if (points > taskPool) {
    points = taskPool;
  }

  points = Number(points.toFixed(2));

  if (points <= 0) continue;

  output.push({
    json: {
      user_id: user.user_id,
      points,
